// Function to check if a stream is found in the process
GF_Err isoffin_process(ISOMReader *isom, GF_Filter *filter, const char *stream_id) {
    GF_Err err;
    GF_ISOMTrack *track;
    GF_ISOMTrackList *track_list;

    // Get the track list from the ISOMReader
    track_list = isom->tracks;

    // Iterate through each track in the list
    while (track_list) {
        track = track_list->track;
        // Check if the track's stream ID matches the given stream ID
        if (strcmp(track->stream_id, stream_id) == 0) {
            // If a matching track is found, return success
            return GF_OK;
        }
        // Move to the next track
        track_list = track_list->next;
    }

    // If no matching track is found, return an error
    return GF_ERR_NOT_FOUND;
}

int main() {
    GF_Err err;
    ISOMReader *isom;
    GF_Filter *filter;
    const char *stream_id = "video_001";

    // Initialize ISOMReader
    isom = isomReaderNew();
    if (!isom) {
        fprintf(stderr, "Failed to initialize ISOMReader\n");
        return EXIT_FAILURE;
    }

    // Initialize GF_Filter
    filter = gf_filter_new(isom);
    if (!filter) {
        fprintf(stderr, "Failed to initialize GF_Filter\n");
        isomReaderDel(isom);
        return EXIT_FAILURE;
    }

    // Process the media stream
    err = isoffin_process(isom, filter, stream_id);
    if (err == GF_OK) {
        printf("Stream '%s' found in the process\n", stream_id);
    } else if (err == GF_ERR_NOT_FOUND) {
        printf("Stream '%s' not found in the process\n", stream_id);
    } else {
        fprintf(stderr, "Error processing stream: %s\n", gf_err_to_string(err));
    }

    // Clean up
    gf_filter_del(filter);
    isomReaderDel(isom);

    return EXIT_SUCCESS;
}
