    struct list_head request_list;
    spinlock_t lock;
};

// Function to handle USB request completion
static void dwc3_gadget_giveback(struct dwc3_gadget *dwc3, struct usb_request *req) {
    struct usb_gadget *gadget = &dwc3->gadget;
    struct dwc3_request *dwc3_req = to_dwc3_request(req);

