    usb_gadget_set_runtime_pm_state(gadget, USB_GADGET_STATE_IDLE);

    // Unlock the list
    spin_unlock(&dwc3->lock);

    // Call the default completion function
    usb_gadget_request_complete(gadget, req);
}
