// Function to extract a file from a ZIP archive
int extract_or_test_entrylist(ZIPEntry *entries, int count, const char *output_dir) {
    int i;
    for (i = 0; i < count; i++) {
        char filepath[256];
        snprintf(filepath, sizeof(filepath), "%s/%s", output_dir, entries[i].filename);

        // Check if the file already exists and handle overwrite condition
        if (access(filepath, F_OK) == 0) {
            printf("File '%s' already exists. Overwrite? (y/n): ", entries[i].filename);
            char response;
            scanf(" %c", &response);
            if (response != 'y') {
                printf("File extraction skipped.\n");
                continue;
            }
        }

        // Open the output file for writing
        FILE *output_file = fopen(filepath, "wb");
        if (!output_file) {
            perror("Failed to open output file");
            return -1;
        }

        // Seek to the file offset in the ZIP archive
