int dxtory_decode_v1_420(AVCodecContext *avctx, AVFrame *frame, int *got_frame, AVPacket *pkt) {
    // Validate packet size
    if (pkt->size < avctx->width * avctx->height * 3 / 2) {
        av_log(avctx, AV_LOG_ERROR, "Packet size is too small for the given frame size.\n");
        return AVERROR_INVALIDDATA;
    }

    // Allocate frame buffer if not already allocated
    if (!frame->data[0]) {
        int ret = av_frame_get_buffer(frame, 0);
        if (ret < 0) {
            av_log(avctx, AV_LOG_ERROR, "Failed to allocate frame buffer.\n");
            return ret;
        }
    }

    // Decode the YUV420P frame
    ret = avcodec_send_packet(avctx, pkt);
    if (ret < 0) {
        av_log(avctx, AV_LOG_ERROR, "Failed to send packet to the decoder.\n");
        return ret;
    }

    ret = avcodec_receive_frame(avctx, frame);
    if (ret == AVERROR(EAGAIN) || ret == AVERROR_EOF) {
        *got_frame = 0;
        return 0;
    } else if (ret < 0) {
        av_log(avctx, AV_LOG_ERROR, "Failed to receive frame from the decoder.\n");
        return ret;
    }

    *got_frame = 1;
    return 0;
}
