bool UnZip(const QString &zipFilePath, const QString &destDirPath)
{
    // Check if the ZIP file exists
    if (!QFile::exists(zipFilePath)) {
        qDebug() << "Error: ZIP file does not exist.";
        return false;
    }

    // Check if the destination directory exists
    QDir destDir(destDirPath);
    if (!destDir.exists()) {
        qDebug() << "Error: Destination directory does not exist.";
        return false;
    }

    // Ensure the destination directory is writable
    if (!destDir.isWritable()) {
        qDebug() << "Error: Destination directory is not writable.";
        return false;
    }

    // Create a QZip object to open the ZIP file
    QZip zip(zipFilePath);
    if (!zip.open(QIODevice::ReadOnly)) {
        qDebug() << "Error: Failed to open ZIP file.";
        return false;
    }

    // Iterate over all entries in the ZIP file
    while (!zip.atEnd()) {
        QZipEntry entry = zip.nextEntry();
        if (!entry.isValid()) {
            qDebug() << "Error: Invalid entry in ZIP file.";
            continue;
        }

        // Extract the file name
        QString fileName = entry.name();
        QString destFilePath = destDir.filePath(fileName);

        // Check if the file name is a directory
        if (entry.isDir()) {
            // Create the directory
            if (!QDir().mkpath(destFilePath)) {
                qDebug() << "Error: Failed to create directory:" << destFilePath;
                continue;
            }
        } else {
            // Extract the file
            QFile file(destFilePath);
            if (!file.open(QIODevice::WriteOnly | QIODevice::Text)) {
                qDebug() << "Error: Failed to open file for writing:" << destFilePath;
