```cpp
#include <Eigen/Dense>
#include <random>

// Define a function to perform vectorized uniform rejection sampling
Eigen::MatrixXd vectorizedUniformRejectionSampling(int batch_size, int sample_size, double lower_bound, double upper_bound) {
    // Initialize the PhiloxRandom generator
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<> dis(lower_bound, upper_bound);

    // Create a matrix to store the generated random numbers
    Eigen::MatrixXd random_numbers(batch_size, sample_size);

    // Loop through each batch and sample
    for (int i = 0; i < batch_size; ++i) {
        for (int j = 0; j < sample_size; ++j) {
            // Generate a random number using PhiloxRandom
            double random_value = dis(gen);

            // Store the random number in the matrix
            random_numbers(i, j) = random_value;
        }
    }

    return random_numbers;
}

int main() {
    // Example usage
    int batch_size = 10;
    int sample_size = 20;
    double lower_bound = 0.0;
    double upper_bound = 1.0;

    Eigen::MatrixXd random_numbers = vectorizedUniformRejectionSampling(batch_size, sample_size, lower_bound, upper_bound);

    // Output the generated random numbers
    std::cout << "Generated random numbers:\n" << random_numbers << std::endl;

    return 0;
}
