#include <iostream>
#include <string>
#include <unordered_map>

// Define a class to represent XML parsing states
class XmlPrologTok {
public:
    enum State {
        START,
        IN_ENTITY,
        IN_CONTENT
    };
    State state;
    std::string entity;
    std::string content;
};

// Define a class to represent an XML parser
class XmlParser {
public:
    XmlParser() : state(XmlPrologTok::START) {}

    void processEntity(const std::string& entity) {
        switch (state) {
            case XmlPrologTok::START:
                if (entity == "&lt;") {
                    state = XmlPrologTok::IN_ENTITY;
                    this->entity = entity;
                } else if (entity == "&gt;") {
                    state = XmlPrologTok::IN_ENTITY;
                    this->entity = entity;
                } else if (entity == "&amp;") {
                    state = XmlPrologTok::IN_ENTITY;
                    this->entity = entity;
                } else if (entity == "&apos;") {
                    state = XmlPrologTok::IN_ENTITY;
                    this->entity = entity;
                } else if (entity == "&quot;") {
                    state = XmlPrologTok::IN_ENTITY;
                    this->entity = entity;
                } else {
                    state = XmlPrologTok::IN_CONTENT;
                    this->content = entity;
                }
                break;
            case XmlPrologTok::IN_ENTITY:
                if (entity == ";") {
                    state = XmlPrologTok::IN_CONTENT;
                    handleEntity();
                } else {
                    this->entity += entity;
                }
                break;
            case XmlPrologTok::IN_CONTENT:
                this->content += entity;
                break;
        }
    }

    void handleEntity() {
        std::unordered_map<std::string, std::string> entityMap = {
            {"&lt;", "<"},
            {"&gt;", ">"},
            {"&amp;", "&"},
            {"&apos;", "'"},
            {"&quot;", "\""}
        };
        if (entityMap.find(entity) != entityMap.end()) {
            content = entityMap[entity];
        } else {
            std::cerr << "Unknown entity: " << entity << std::endl;
        }
    }

    std::string getProcessedContent() const {
        return content;
    }

private:
    XmlPrologTok state;
    std::string content;
};

int main() {
    XmlParser parser;
    parser.processEntity("&lt;");
    parser.processEntity("world");
    parser.processEntity("&gt;");
    std::cout << "Processed Content: " << parser.getProcessedContent() << std::endl;
    return 0;
}
