// Function to parse S/MIME message
void empe_app_smime_parse(const char *smime_message) {
    CamelMimeMessage *message;
    CamelMimePart *part;
    CamelCipherContext *cipher_context;
    CamelMimeBody *body;
    const char *decrypted_data;
    size_t decrypted_size;

    // Create a new MIME message from the S/MIME message string
    message = camel_mime_message_new_from_string(smime_message);

    // Get the first part of the message
    part = camel_mime_message_get_first_part(message);

    // Ensure the part is a MIME body
    if (camel_mime_part_get_content_type(part) && strcmp(camel_mime_part_get_content_type(part), "application/pkcs7-mime") == 0) {
        body = camel_mime_part_get_body(part);

        // Create a new cipher context for decryption
        cipher_context = camel_cipher_context_new("aes-256-cbc", "cbc", "12345678901234567890123456789012");

        // Decrypt the body
        decrypted_data = camel_cipher_context_decrypt_sync(cipher_context, body->data, body->data_len, &decrypted_size);

        // Update the message validity
        e_mail_part_update_validity(part, decrypted_data, decrypted_size);

        // Print the decrypted data
        printf("Decrypted Data: %s\n", decrypted_data);

        // Clean up
        g_free(decrypted_data);
        camel_cipher_context_free(cipher_context);
        camel_mime_body_free(body);
        camel_mime_part_free(part);
        camel_mime_message_free(message);
    } else {
        printf("Invalid S/MIME message format.\n");
    }
}

