void *dma_alloc_from_contiguous(struct device *dev, size_t size, dma_addr_t *dma_handle) {
    // Check if the device supports contiguous memory allocation
    if (!dev->dma_coherent) {
        return NULL;
    }

    // Allocate contiguous memory pages using cma_alloc
    void *ptr = cma_alloc(dev->dma_coherent, size, dma_handle, GFP_KERNEL);
    if (!ptr) {
