        size_t offset = CONFIG_CMA_ALIGNMENT - ((uintptr_t)ptr % CONFIG_CMA_ALIGNMENT);
        // Move the pointer to the aligned address
        ptr = (void *)((uintptr_t)ptr + offset);
        // Adjust the DMA handle accordingly
        *dma_handle += offset;
    }

    return ptr;
}
