#define PPD_HEADER "%%!PS-Adobe-3.0\n"
#define PPD_END "%%EOF\n"

int _ppdCreateFromIPP(ipp_t *ipp, cupsFile_t *ppd_file) {
    if (ipp == NULL || ppd_file == NULL) {
        fprintf(stderr, "Invalid IPP or PPD file pointer\n");
        return -1;
    }

    // Write PPD header
    if (cupsFilePuts(ppd_file, PPD_HEADER) < 0) {
        fprintf(stderr, "Failed to write PPD header\n");
        return -1;
    }

    // Process IPP attributes
    ipp_attribute_t *attr;
    ippGetFirstAttribute(ipp, &attr);
    while (attr != NULL) {
        if (ippGetNextAttribute(ipp, &attr) < 0) {
            fprintf(stderr, "Failed to get next IPP attribute\n");
            return -1;
        }

        // Write attribute name and value to PPD
        if (cupsFilePuts(ppd_file, "%%BeginFeature: ") < 0) {
            fprintf(stderr, "Failed to write %%BeginFeature\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, attr->name) < 0) {
            fprintf(stderr, "Failed to write attribute name\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, "\n") < 0) {
            fprintf(stderr, "Failed to write newline\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, "  %%Default: ") < 0) {
            fprintf(stderr, "Failed to write %%Default\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, ippGetString(attr, 0, NULL)) < 0) {
            fprintf(stderr, "Failed to write default value\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, "\n") < 0) {
            fprintf(stderr, "Failed to write newline\n");
            return -1;
        }
        if (cupsFilePuts(ppd_file, "  %%EndFeature\n") < 0) {
            fprintf(stderr, "Failed to write %%EndFeature\n");
            return -1;
        }
    }

    // Write PPD end
    if (cupsFilePuts(ppd_file, PPD_END) < 0) {
        fprintf(stderr, "Failed to write PPD end\n");
        return -1;
    }

    // Close the PPD file
    if (cupsFileClose(ppd_file) < 0) {
        fprintf(stderr, "Failed to close PPD file\n");
        return -1;
    }

    return 0;
}
