// Function to perform spatial max pooling on a tensor using Eigen
void SpatialMaxPool(const Eigen::Tensor<float, 4>& input, Eigen::Tensor<float, 4>& output, int kernel_size, int stride) {
    // Ensure input and output tensors have the same dimensions
    assert(input.dimensions() == output.dimensions());

    // Get the dimensions of the input tensor
    int batch_size = input.dimension(0);
    int channels = input.dimension(1);
    int height = input.dimension(2);
    int width = input.dimension(3);

    // Compute the output dimensions
    int out_height = (height - kernel_size) / stride + 1;
    int out_width = (width - kernel_size) / stride + 1;

    // Initialize the output tensor with zeros
    output.setZero();

    // Perform spatial max pooling
    for (int b = 0; b < batch_size; ++b) {
        for (int c = 0; c < channels; ++c) {
            for (int h = 0; h < out_height; ++h) {
                for (int w = 0; w < out_width; ++w) {
                    // Extract the current pooling window from the input
                    Eigen::Tensor<float, 2> window = input.slice(b, c, h * stride, h * stride + kernel_size, w * stride, w * stride + kernel_size);

                    // Find the maximum value in the window
                    float max_value = window.maxCoeff();

                    // Store the maximum value in the output
                    output(b, c, h, w) = max_value;
                }
            }
        }
    }
}

int main() {
