    Eigen::Tensor<float, 4> input(2, 3, 4, 4); // 2 batches, 3 channels, 4x4 input size
    Eigen::Tensor<float, 4> output(2, 3, 3, 3); // 2 batches, 3 channels, 3x3 output size

