// Function to handle ALPN protocol negotiation and session caching
int bearssl_connect_step3(struct ssl_context *ctx, struct conn *conn, const char *alpn_protocols) {
    // Check if ALPN protocols are provided
    if (alpn_protocols == NULL) {
        return SSL_ERROR_NO_ALPN_PROTOCOLS;
    }

    // Attempt to find a matching ALPN protocol
    const struct ssl_alpn_proto *alpn = ssl_alpn_find(ctx, alpn_protocols);
    if (alpn == NULL) {
        return SSL_ERROR_NO_ALPN_PROTOCOLS;
    }

    // Allocate memory for session parameters
    struct ssl_session *session = ssl_session_new();
    if (session == NULL) {
        return SSL_ERROR_NO_MEMORY;
    }

    // Initialize session parameters
    ssl_session_set_protocol(session, alpn->protocol);
    ssl_session_set_cipher(session, ctx->session->cipher);
    ssl_session_set_mac(session, ctx->session->mac);

    // Set session in connection context
    conn->session = session;

    // Update connection state
    conn->state = SSL_CONNECTED;

    return SSL_SUCCESS;
}
