void ZRLE_DECODE(rdr::InStream &in, unsigned char *buffer, int width, int height) {
    unsigned char *tempBuffer = new unsigned char[width * height * 3];
    int tempBufferIndex = 0;
    int rleCount = 0;
    int paletteIndex = 0;
    int currentColor[3] = {0, 0, 0};

    while (tempBufferIndex < width * height * 3) {
        int byte = in.get();
        if (byte == 0) {
            // Palette entry
            currentColor[0] = in.get();
            currentColor[1] = in.get();
            currentColor[2] = in.get();
            paletteIndex++;
        } else if (byte > 127) {
            // Run of the same color
            rleCount = byte - 127;
            for (int i = 0; i < rleCount; i++) {
                tempBuffer[tempBufferIndex++] = currentColor[0];
                tempBuffer[tempBufferIndex++] = currentColor[1];
                tempBuffer[tempBufferIndex++] = currentColor[2];
            }
        } else {
            // Run of the same color with a palette entry
            rleCount = byte;
            for (int i = 0; i < rleCount; i++) {
                tempBuffer[tempBufferIndex++] = currentColor[0];
                tempBuffer[tempBufferIndex++] = currentColor[1];
                tempBuffer[tempBufferIndex++] = currentColor[2];
            }
            paletteIndex++;
