```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <talloc.h>
#include <notify.h>

typedef struct {
    TALLOC_CTX *ctx;
    notify_handle *handle;
    char *path;
} ChangeNotify;

ChangeNotify *change_notify_create(const char *path) {
    ChangeNotify *notify = talloc_zero(NULL, ChangeNotify);
    if (!notify) {
        perror("talloc_zero failed");
        return NULL;
    }

    // Sanitize the path by removing trailing '/.'
    notify->path = talloc_strdup(notify, path);
    if (!notify->path) {
        perror("talloc_strdup failed");
        talloc_free(notify);
        return NULL;
    }

    // Remove trailing '/' and '.'
    size_t len = strlen(notify->path);
    while (len > 0 && (notify->path[len - 1] == '/' || notify->path[len - 1] == '.')) {
        notify->path[len - 1] = '\0';
        len--;
    }

    // Initialize the notification handle
    notify->handle = notify_add(notify->ctx, notify->path, NULL, NULL, NULL);
    if (!notify->handle) {
        perror("notify_add failed");
        talloc_free(notify->path);
        talloc_free(notify);
        return NULL;
    }

    return notify;
}

void change_notify_free(ChangeNotify *notify) {
    if (notify) {
        notify_remove(notify->handle);
        talloc_free(notify->path);
        talloc_free(notify);
    }
}
