// Function to safely increment the write counter for a BPF map
int bpf_map_mmap_open(struct bpf_map *map, struct vm_area_struct *vma) {
    // Check if the VM_MAYWRITE flag is set in the vm_area_struct
    if (vma->vm_flags & VM_MAYWRITE) {
        // Lock the mutex to ensure thread safety
        mutex_lock(&map->mutex);

        // Increment the write counter
        map->write_count++;

        // Unlock the mutex
