```cpp
#include <mongoose.h>
#include <iostream>
#include <fstream>
#include <string>

class HTTPserver {
public:
    HTTPserver(int httpPort, int httpsPort, const std::string& sslCertFile, const std::string& sslKeyFile) {
        // Initialize Mongoose
        mg_init();

        // Create a listener for HTTP
        struct mg_connection* httpListener = mg_bind(&mgr, "0.0.0.0:" + std::to_string(httpPort), ev_handler);
        if (httpListener == nullptr) {
            std::cerr << "Failed to create HTTP listener" << std::endl;
            mg_exit();
            return;
        }

        // Create a listener for HTTPS
        struct mg_connection* httpsListener = mg_bind(&mgr, "0.0.0.0:" + std::to_string(httpsPort), ev_handler);
        if (httpsListener == nullptr) {
            std::cerr << "Failed to create HTTPS listener" << std::endl;
            mg_exit();
            return;
        }

        // Load SSL certificates
        if (!loadSSLConfig(sslCertFile, sslKeyFile)) {
            std::cerr << "Failed to load SSL configuration" << std::endl;
            mg_exit();
            return;
        }

        // Start the Mongoose event loop
        mg_start(&mgr);
    }

    ~HTTPserver() {
        mg_exit();
    }

private:
    struct mg_mgr mgr;

    bool loadSSLConfig(const std::string& sslCertFile, const std::string& sslKeyFile) {
        // Check if SSL certificate and key files exist
        if (!std::ifstream(sslCertFile).good()) {
            std::cerr << "SSL certificate file not found: " << sslCertFile << std::endl;
            return false;
        }

        if (!std::ifstream(sslKeyFile).good()) {
            std::cerr << "SSL key file not found: " << sslKeyFile << std::endl;
            return false;
        }

        // Configure SSL on the listeners
        mg_set_option(httpListener, "ssl_cert", sslCertFile.c_str());
        mg_set_option(httpListener, "ssl_key", sslKeyFile.c_str());

        mg_set_option(httpsListener, "ssl_cert", sslCertFile.c_str());
        mg_set_option(httpsListener, "ssl_key", sslKeyFile.c_str());

        return true;
    }

    static void ev_handler(struct mg_connection* conn, int ev, void* ev_data) {
        switch (ev) {
            case MG_EV_HTTP_REQUEST:
                handleHTTPRequest(conn, ev_data);
                break;
            case MG_EV_CLOSE:
                std::cout << "Connection closed" << std::endl;
                break;
            default:
                break;
        }
    }

    static void handleHTTPRequest(struct mg_connection* conn, void* ev_data) {
        struct mg_http_message* hm = (struct mg_http_message*)ev_data;
        std::string request = hm->body;

        std::cout << "Received request: " << request << std::endl;

        // Send a simple HTTP response
        char response[] = "HTTP/1.1 200 OK\r\n"
                          "Content-Type: text/plain\r\n"
                          "Content-Length: 13\r\n"
                          "\r\n"
                          "Hello, World!";
        mg_http_send_response(conn, response, sizeof(response) - 1);
    }
};

int main() {
    int httpPort = 8080;
    int httpsPort = 8443;
    std::string sslCertFile = "path/to/your/certificate.pem";
    std::string sslKeyFile = "path/to/your/private_key.pem";

    HTTPserver server(httpPort, httpsPort, sslCertFile, sslKeyFile);

    // Keep the program running
    while (true) {
        mg_mgr_poll(&server.mgr, 1000);
    }

    return 0;
}
